package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToListTest : TestBase() {

    @Test
    fun testToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = ArrayList<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)

        job.cancel()

        assertEquals(listOf(1, 2), acc)
    }

    @Test
    fun testToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = LinkedHashSet<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toSet(acc)
        }

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(1)

        job.cancel()

        assertEquals(setOf(1, 2), acc)
    }
}
